#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int L, R, N;
        scanf("%d %d %d", &L, &R, &N);
        int fib[100] = {0, 1};
        for (int i = 2; i < 100; i++) {
            fib[i] = fib[i-1] + fib[i-2];
        }
        int count = 0;
        for (int i = 0; i < 100; i++) {
            if (fib[i] >= L && fib[i] <= R) {
                count++;
            }
        }
        if (N > count) {
            printf("-1\n");
        } else {
            int index = 0;
            for (int i = 0; i < 100; i++) {
                if (fib[i] >= L && fib[i] <= R) {
                    index++;
                    if (index == N) {
                        printf("%d ", fib[i]);
                        for (int j = 0; j < fib[i]; j++) {
                            printf(".");
                        }
                        printf("\n");
                        break;
                    }
                }
            }
        }
    }
    return 0;
}

