import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            int N = sc.nextInt();
            int[] fib = new int[100];
            fib[0] = 0;
            fib[1] = 1;
            for (int i = 2; i < 100; i++) {
                fib[i] = fib[i-1] + fib[i-2];
            }
            int count = 0;
            for (int i = 0; i < 100; i++) {
                if (fib[i] >= L && fib[i] <= R) {
                    count++;
                }
            }
            if (N > count) {
                System.out.println(-1);
            } else {
                int index = 0;
                for (int i = 0; i < 100; i++) {
                    if (fib[i] >= L && fib[i] <= R) {
                        index++;
                        if (index == N) {
                            System.out.print(fib[i] + " ");
                            for (int j = 0; j < fib[i]; j++) {
                                System.out.print(".");
                            }
                            System.out.println();
                            break;
                        }
                    }
                }
            }
        }
    }
}

